/* eslint-disable */

/**
 * JS-facing builder for streaming tensor bytes directly into WASM linear
 * memory.
 *
 * The naive path (`backend.set_tensor(name, new Uint8Array(megabytes))`)
 * requires JS to materialize the entire tensor as one contiguous
 * Uint8Array before crossing the boundary. For qwen-7b's FFN matrices
 * (~14 MB Q4_K each) this is fine on a laptop but blows the JS heap on
 * a 128 MB CF Worker, especially because the Worker is *also* holding
 * the previous phase's tensors awaiting eviction.
 *
 * `TensorBuilder` lets the host stream the row in chunks: allocate a
 * fixed-capacity Vec on the WASM side, append each chunk as it arrives
 * from R2 (Range responses are themselves chunked), and finalize by
 * handing the Vec to the backend in a zero-copy move. Peak JS heap
 * drops to one chunk's worth of bytes (kilobytes, not megabytes).
 */
export class TensorBuilder {
    free(): void;
    [Symbol.dispose](): void;
    /**
     * Append a chunk of bytes to the in-flight buffer. Safe to call
     * many times; the underlying Vec grows in amortized O(1) when the
     * initial capacity was right.
     */
    append(chunk: Uint8Array): void;
    /**
     * Hand the accumulated bytes to the backend under `name` and
     * consume the builder. After this call the builder is unusable.
     * The Vec move is zero-copy — no extra allocation crosses into
     * the backend.
     */
    finish(backend: WasmHostBackend, name: string): void;
    /**
     * Pre-allocate `capacity` bytes. Caller is expected to pass the
     * exact final size (known from the knot metadata `length` field);
     * passing a smaller value forces re-allocations on each `append`,
     * passing a larger value wastes WASM memory. Either is correct,
     * but exact is what the worker should pass.
     */
    constructor(capacity: number);
}

export class WasmGemma4Pipeline {
    private constructor();
    free(): void;
    [Symbol.dispose](): void;
    forward_range_attn_chunk(input: Float32Array, layer: number, start_pos: number, seq_len: number, is_first_layer: boolean): void;
    forward_range_ffn_down_chunk(layer: number, seq_len: number, is_last_layer: boolean): Float32Array;
    forward_range_ffn_gate_chunk(layer: number, seq_len: number): void;
    forward_range_ffn_up_chunk(layer: number, seq_len: number): void;
    /**
     * Borrow-construct from a host backend. Same `&WasmHostBackend` rule
     * as WasmLlamaPipeline (taking by value triggers wasm-bindgen
     * `__destroy_into_raw` on the JS handle and invalidates subsequent
     * `set_tensor` calls — see WasmLlamaPipeline::from_backend).
     * `kv_base_layer` / `kv_num_layers`: fluid-memory KV alloc (#31). On
     * gemma4-31b a single-layer trisplit worker passing `(17, 1)` cuts
     * the cache from ~503 MiB to ~8 MiB and is the difference between
     * fitting and OOMing on the 128 MiB Worker isolate cap.
     */
    static from_backend(backend: WasmHostBackend, config_json: string | null | undefined, payload_offset: number, kv_base_layer?: number | null, kv_num_layers?: number | null): WasmGemma4Pipeline;
    get_batch_hb(seq_len: number): Float32Array;
    get_batch_hb_in_ptr(): number;
    /**
     * Wave-23 Bug B (deeper fix, Path B): caller-provided output buffer.
     * JS allocates a Float32Array of length `seq_len * intermediate_size`
     * and passes it in; wasm fills it via `Float32Array::copy_from(&slice)`,
     * which uses `set` semantics writing INTO a JS-owned ArrayBuffer.
     *
     * Why this is safer than the `Vec<f32>`-returning `get_batch_hb`:
     * the `Vec<f32>` return path runs (1) Rust `to_vec()`, (2)
     * wasm-bindgen `__wbindgen_malloc` for an export staging buffer in
     * WASM linear memory, (3) JS-side
     * `getFloat32ArrayMemory0().subarray(ptr/4, ptr/4 + len)`, (4)
     * `.slice()` to copy out, (5) `__wbindgen_free`. Steps (2)+(3) are
     * the failure surface: if `__wbindgen_malloc` triggers `memory.grow`
     * mid-call, the cached Float32Array view JS uses for `subarray`
     * becomes invalid even with the wave-22 buffer-identity shim — the
     * shim runs at view-fetch time, but the subsequent `subarray` op
     * can still race a grow inside the same call frame. With this API,
     * JS owns the destination buffer and `Float32Array::copy_from`
     * writes into it without any export-side malloc or subarray call.
     *
     * Returns `Err` if `out.length() < seq_len * intermediate_size`.
     * Path A (boot-time pre-grow in `from_knot_with_kv_range`) is the
     * primary defense; this Path B export is the belt-and-suspenders
     * fallback if Path A doesn't fully eliminate Bug B post-deploy.
     * Existing `get_batch_hb` callers are unaffected — JS migrates
     * only when ready.
     */
    get_batch_hb_into(seq_len: number, out: Float32Array): void;
    get_batch_x_in_ptr(): number;
    get_batch_xb(seq_len: number): Float32Array;
    get_batch_xb_in_ptr(): number;
    get_residual(seq_len: number): Float32Array;
    /**
     * True when `layer` is a global-attention layer (Gemma3/4 sliding-
     * window dispatch). Surfaced for diagnostic dumps in
     * `gemma4-pipeline-smoke` and the worker boot.
     */
    is_global_layer(layer: number): boolean;
    lm_head_only(input: Float32Array, seq_len: number): Float32Array;
    set_batch_hb(input: Float32Array): void;
    set_batch_x(input: Float32Array): void;
    /**
     * Fused split-c setter (wave-22 Fix A). Takes the concatenated
     * `[batch_x | batch_hb]` buffer in a single wasm-bindgen call —
     * halving the JS↔wasm boundary cost vs back-to-back
     * `set_batch_x` + `set_batch_hb`. See SPLIT_C_BOTTLENECK_INVESTIGATION
     * for the +6.0% TPS prediction on gemma4-31b trisplit.
     */
    set_batch_x_and_hb(combined: Float32Array, hidden_dim: number, seq_len: number): void;
    set_batch_xb(input: Float32Array): void;
    /**
     * Wave-23 Bug B Path E: combined split-b call. Replaces the
     * `set_batch_xb` + `forward_range_ffn_gate_chunk` +
     * `forward_range_ffn_up_chunk` + `get_batch_hb*` four-call sequence
     * with ONE wasm-bindgen export.
     *
     * The four-call sequence was the residual failure mode after Paths
     * A-D: each call is a separate JS frame, and `memory.grow` could
     * fire between two of them, leaving JS-side typed-array views or
     * caller-provided Float32Array buffers stale by the time the next
     * call ran. Path E collapses everything into one synchronous wasm
     * execution. The return-`Vec<f32>` allocation that wasm-bindgen
     * stages via `__wbindgen_malloc` is the LAST allocation in the
     * frame, so the JS-side `getArrayF32FromWasm0` read sees a stable
     * `wasm.memory.buffer` (no further grow can race it).
     *
     * `batch_xb` is the input residual (`seq_len × hidden_dim` floats).
     * Returns `batch_hb` (`seq_len × intermediate_size` floats).
     */
    split_b_chunk(batch_xb: Float32Array, layer: number, seq_len: number): Float32Array;
}

/**
 * JS-facing host-populated weight backend.
 *
 * Constructed from a stringified `tensors` map (the same shape produced by
 * `parse_tensors_json`). The host populates per-tensor bytes via
 * `set_tensor` before invoking the pipeline, and frees them via `evict`.
 */
export class WasmHostBackend {
    free(): void;
    [Symbol.dispose](): void;
    /**
     * Drop tensor bytes from the cache. Called by the host shim after a
     * layer chunk has been consumed by the forward pass.
     */
    evict(names: string[]): void;
    /**
     * `metadata_json` is stringified JSON of either:
     *   - the full knot metadata object (with a top-level `tensors` key), or
     *   - the `tensors` map directly (object of `name → { offset, length, type }`).
     * Both shapes are accepted; the constructor probes for `tensors` first.
     */
    constructor(metadata_json: string);
    /**
     * Insert tensor bytes into the cache. Called once per tensor per layer
     * chunk by the JS host before re-entering the pipeline.
     */
    set_tensor(name: string, bytes: Uint8Array): void;
    /**
     * Return `{ offset, length, tensor_type }` for the given tensor name as
     * a JSON string, or `None` if not in the metadata. JSON-string return
     * (not `JsValue`) sidesteps a wasm-bindgen externref-shim crash where
     * every call to `tensor_info` fired `__rt::throw_null` from inside the
     * generated wrapper — even though the Rust body never produced a null
     * JsValue. Repro stack:
     * `WasmHostBackend.tensor_info → wasmhostbackend_tensor_info externref
     *  shim → __rt::throw_null → __wbindgen_throw`. Returning a primitive
     * `Option<String>` avoids externref entirely and the JS host parses the
     * JSON. The encode + parse cost (~30 bytes once per layer phase) is
     * invisible compared to the per-layer R2 fetch.
     */
    tensor_info(name: string): string | undefined;
}

/**
 * JS-facing pipeline. Wraps the cross-target `NativeLlamaPipeline`. The JS
 * host owns one of these per active session; the underlying Rust struct
 * holds the resolved tensor refs, KV cache, and reusable scratch buffers.
 */
export class WasmLlamaPipeline {
    private constructor();
    free(): void;
    [Symbol.dispose](): void;
    amplituhedron_capture(prefix_hash: bigint, prefix_len: number, layer_lo: number, layer_hi: number, tail_residual: Float32Array, kv_slab: Float32Array): void;
    amplituhedron_clear(): void;
    amplituhedron_enable(on: boolean): void;
    /**
     * On hit, returns `[tail_len, tail..., kv_slab...]`; on miss, returns
     * an empty vector. The first element is exact for current hidden sizes.
     */
    amplituhedron_replay(prefix_hash: bigint, prefix_len: number, layer_lo: number, layer_hi: number): Float32Array;
    amplituhedron_set_max_volumes(n: number): void;
    amplituhedron_stats(): Uint32Array;
    /**
     * Embedding-only forward. Entry stations call this for the first chunk
     * (or each batched chunk) to produce the initial residual stream.
     */
    embed(tokens: Uint32Array, start_pos: number): Float32Array;
    /**
     * Vocabulary-sharded embedding. Returns a residual stream where tokens
     * in `[vocab_start, vocab_end)` are dequantized normally and tokens
     * outside that range produce zero vectors. The coordinator adds all
     * partial results from N cobordism shards (Frobenius μ: A ⊗ A → A).
     */
    embed_range(tokens: Uint32Array, start_pos: number, vocab_start: number, vocab_end: number): Float32Array;
    /**
     * Run a contiguous range of transformer layers over an incoming residual.
     * This is the load-bearing primitive for log-rolling: each station calls
     * `forward_range` over its pinned layer range and hands off the result to
     * the next station.
     *
     * Causal masking is applied internally for `sequence_length > 1`. KV
     * cache is updated for positions `[start_pos, start_pos + sequence_length)`.
     */
    forward_range(residual: Float32Array, start_layer: number, end_layer: number, start_pos: number, sequence_length: number): Float32Array;
    /**
     * Split phase 1: Attention. Uses `[attn_norm, q, k, v, o]`.
     */
    forward_range_attn_chunk(residual: Float32Array, layer: number, start_pos: number, sequence_length: number, is_first_layer: boolean): void;
    /**
     * Split phase 3: FFN Down. Uses `[ffn_down]`.
     * Returns the residual vector if `is_last_layer` is true, otherwise an empty array.
     */
    forward_range_ffn_down_chunk(layer: number, sequence_length: number, is_last_layer: boolean): Float32Array;
    /**
     * Split FFN phase 2 into 2a (gate) and 2b (up + swiglu). The
     * worker is expected to call them sequentially, evicting the
     * gate matrix between the two — see the rationale comment on
     * `NativeLlamaPipeline::forward_range_ffn_gate_chunk`.
     */
    forward_range_ffn_gate_chunk(layer: number, sequence_length: number): void;
    /**
     * Combined gate + up + swiglu path. Retained for callers that
     * don't fluid-memory the FFN halves.
     */
    forward_range_ffn_gate_up_chunk(layer: number, sequence_length: number): void;
    forward_range_ffn_up_chunk(layer: number, sequence_length: number): void;
    /**
     * Borrow-construct from a backend. We take `&WasmHostBackend` (not by
     * value) so the JS handle stays alive for subsequent
     * `set_tensor` / `evict` / `tensor_info` calls. Fluid-memory boot
     * loads tensors per layer phase, then forwards, then evicts — that
     * pattern requires the backend handle to remain valid past pipeline
     * construction.
     *
     * Previous shape `pub fn from_backend(backend: WasmHostBackend, ...)`
     * caused a `__rt::throw_null` ("null pointer passed to rust") panic
     * on every set_tensor that ran after pipeline construction; the
     * wasm-bindgen-generated `_assertClass + __destroy_into_raw` chain
     * zeros `__wbg_ptr` when the wrapper is taken by value. Switching
     * to `&WasmHostBackend` keeps the wrapper alive on the JS side.
     *
     * `config_json` is either a stringified `KnotConfig` or `null`. Passing
     * `null` falls back to TinyLlama defaults (matches the legacy 1B-knot
     * path; see `TransformerConfig::default` in `model.rs`).
     * `kv_base_layer` / `kv_num_layers`: optional fluid-memory KV alloc.
     * Pass `(layer_index_we_own, 1)` from a single-layer trisplit worker
     * to shrink the KV cache from full-model to one-layer (~503 MiB →
     * ~8 MiB on gemma4-31b global heads). `None` defaults preserve legacy
     * whole-model alloc — back-compat for callers that pre-date #31.
     */
    static from_backend(backend: WasmHostBackend, config_json: string | null | undefined, payload_offset: number, draft_mode: boolean, resonance_threshold: number, kv_base_layer?: number | null, kv_num_layers?: number | null): WasmLlamaPipeline;
    /**
     * Run the autoregressive generation loop. Returns the newly generated
     * tokens (excludes the prompt). Same semantics as the native NAPI path.
     */
    generate(prompt_tokens: Uint32Array, max_new_tokens: number): Uint32Array;
    get_batch_hb(seq_len: number): Float32Array;
    get_batch_hb_in_ptr(): number;
    get_batch_x_in_ptr(): number;
    get_batch_xb(seq_len: number): Float32Array;
    get_batch_xb_in_ptr(): number;
    get_kv_slab(layer_lo: number, layer_hi: number, prefix_len: number): Float32Array;
    /**
     * Current decode position (number of tokens fed so far).
     */
    get_pos(): number;
    /**
     * Read the first `seq_len * hidden_dim` floats out of the pipeline's
     * `batch_x` buffer. Used by the liquid-mesh `/forward-one` path:
     * the worker calls `forward_range_ffn_down_chunk(layer, seq_len, false)`
     * to leave the post-residual-add output in `batch_x`, then calls this
     * to extract the residual. Returning `Vec<f32>` from the kernel
     * directly (with `is_last_layer=true`) was throwing
     * "Invalid array buffer length" on the JS side after the kernel
     * completed — likely a wasm-bindgen multivalue-return path issue
     * triggered by some interaction between this kernel's `vec!` and
     * the post-grow memory state. Splitting the access avoids it.
     */
    get_residual(seq_len: number): Float32Array;
    /**
     * Apply final norm + lm_head to a residual stream and return logits for
     * the LAST token in the chunk (the next-token-prediction row). Exit
     * stations call this.
     */
    lm_head(residual: Float32Array, sequence_length: number): Float32Array;
    /**
     * Fluid-memory vocabulary-sharded lm_head. The host pre-loads only
     * the rows of `output_weight` for `[vocab_start, vocab_end)` under
     * the synthetic name `lm_head_partial_weight`. Peak resident weight
     * bytes is one shard's slice (~55 MiB Q6_K for an 8-way qwen-7b
     * shard) — fits inside the 128 MiB Worker cap, where the full
     * 447 MiB tensor cannot.
     *
     * See `NativeLlamaPipeline::lm_head_partial` for the host-side flow.
     */
    lm_head_partial(residual: Float32Array, sequence_length: number, vocab_start: number, vocab_end: number): Float32Array;
    /**
     * Vocabulary-sharded lm_head. Computes partial logits over
     * `[vocab_start, vocab_end)` only, returning a vector of length
     * `(vocab_end - vocab_start)`. The coordinator concatenates partials
     * from all cobordism shards (comultiplication Δ: A → A ⊗ A).
     */
    lm_head_range(residual: Float32Array, sequence_length: number, vocab_start: number, vocab_end: number): Float32Array;
    memo_clear(): void;
    /**
     * Per-(layer, op) hit-rate breakdown. Flat layout, four u32s per
     * entry: `[layer, op, hits, misses, layer, op, hits, misses, ...]`.
     * `op` is the u8 op-id from the `OP_*` constants in `matvec_memo.rs`,
     * widened to u32 for the JS Uint32Array boundary. Iteration order
     * follows the underlying HashMap and is therefore not stable
     * across calls; the bench should sort by (layer, op) before
     * rendering. Length is always a multiple of 4. Empty when no
     * probes have run.
     */
    memo_detailed_stats(): Uint32Array;
    /**
     * Pisot drift histogram (Death #5 — Connes-Kreimer/Pisot residue).
     * Returns `[luminary, total, drift_min_q12, drift_mean_q12, drift_max_q12]`.
     * `drift_*_q12 = (drift * 4096.0) as u32` — fixed-point, JS divides by 4096.
     * `luminary_threshold_q12` likewise: caller passes `(threshold * 4096) as u32`.
     * Honest scope: this is the f32 surrogate flagged at
     * `matvec_memo::pisot_drift`. The Lean witness lives on integer Lucas
     * pairs (`PisotMitosisManifold.mitosis_restores_invariant`); this
     * accessor exposes the surrogate distribution, not a Hopf-algebraic
     * renormalization. Use it to detect when the working set drifts off
     * the φ-attractor — that is the operational meaning of "halting
     * residue" the FORMAL_LEDGER claims for RMSNorm but RMSNorm itself
     * does not directly compute.
     */
    memo_drift_summary(luminary_threshold_q12: number): Uint32Array;
    memo_enable(on: boolean): void;
    /**
     * Direct Pisot-drift probe — compute the surrogate on an arbitrary
     * f32 vector WITHOUT inserting into the cache. Useful for validating
     * the surrogate scale on healthy inputs without needing a working
     * kernel chain. Returns drift × 4096 in q12 fixed-point; JS divides
     * by 4096 to recover f32. Returns u32::MAX for non-finite drifts.
     */
    memo_probe_drift(x: Float32Array): number;
    memo_set_max_entries(n: number): void;
    memo_set_tau_squared(tau_sq: number): void;
    /**
     * Aggregate stats packed as a 3-element Vec<u32>:
     * `[hits, misses, evictions]`.
     */
    memo_stats(): Uint32Array;
    set_batch_hb(input: Float32Array): void;
    set_batch_x(input: Float32Array): void;
    /**
     * Fused split-c setter (wave-22 Fix A). Takes the concatenated
     * `[batch_x | batch_hb]` buffer in a single wasm-bindgen call —
     * halving the JS↔wasm boundary cost vs back-to-back
     * `set_batch_x` + `set_batch_hb`. See SPLIT_C_BOTTLENECK_INVESTIGATION
     * for the +6.0% TPS prediction on gemma4-31b trisplit.
     */
    set_batch_x_and_hb(combined: Float32Array, hidden_dim: number, seq_len: number): void;
    set_batch_xb(input: Float32Array): void;
    set_kv_slab(layer_lo: number, layer_hi: number, prefix_len: number, slab: Float32Array): void;
    /**
     * Wave-23 Bug B Path E: combined split-b call for the LLaMA arch
     * (qwen2 / qwen-coder-7b / llama / mistral). Mirrors
     * `WasmGemma4Pipeline::split_b_chunk`. Replaces the four-call
     * `set_batch_xb` + `forward_range_ffn_gate_chunk` +
     * `forward_range_ffn_up_chunk` + `get_batch_hb*` JS-side sequence
     * with ONE wasm-bindgen export.
     *
     * See `docs/bug-b-path-e-result.md` for the full investigation —
     * the four-call sequence was the residual failure mode after
     * Paths A-D: each call is a separate JS frame, and `memory.grow`
     * could fire between two of them, leaving JS-side typed-array
     * views or caller-provided Float32Array buffers stale by the
     * time the next call ran. Path E collapses everything into one
     * synchronous wasm execution. The return-`Vec<f32>` allocation
     * that wasm-bindgen stages via `__wbindgen_malloc` is the LAST
     * allocation in the frame, so the JS-side `getArrayF32FromWasm0`
     * read sees a stable `wasm.memory.buffer` (no further grow can
     * race it).
     *
     * `batch_xb` is the input residual (`seq_len × hidden_dim` floats).
     * Returns `batch_hb` (`seq_len × intermediate_size` floats) — the
     * SwiGLU-fused gate*up output ready to feed `/split-c`.
     */
    split_b_chunk(batch_xb: Float32Array, layer: number, seq_len: number): Float32Array;
}

