/**
 * Result of [`sfm_solve`]: a JSON document describing either the recovered pose
 * or an honest null. Shape:
 *
 * ```json
 * // pose:
 * { "ok": true, "r": [[..],[..],[..]], "t": [x,y,z],
 *   "intrinsics": {"fx":..,"fy":..,"cx":..,"cy":..},
 *   "inliers": 73, "matches": 91, "medianParallaxDeg": 6.2, "confidence": 0.71 }
 * // honest null:
 * { "ok": false, "reason": "...", "confidence": 0.0 }
 * ```
 */
export class WasmSfmResult {
    private constructor();
    free(): void;
    [Symbol.dispose](): void;
    readonly confidence: number;
    /**
     * `true` when a trustworthy pose was recovered; `false` = honest null
     * (caller should fall back, e.g. to the turntable carve).
     */
    readonly isPose: boolean;
    readonly json: string;
}

/**
 * Result of Topological Calibration (Manifold Shift or LUT).
 */
export class WasmTopologicalCalibrationResult {
    private constructor();
    free(): void;
    [Symbol.dispose](): void;
    readonly rgb: Float32Array;
}

/**
 * Result of [`wasm_topology_mask_build_rgb_f32`]: soft alpha `[0,1]^wh` plus serde provenance JSON.
 */
export class WasmTopologyMaskResult {
    private constructor();
    free(): void;
    [Symbol.dispose](): void;
    readonly alpha: Float32Array;
    readonly provenance_json: string;
}

/**
 * JS-callable Whisper STT pipeline.
 *
 * Construction is two-step: the JS host first builds a
 * `WasmHostBackend` (same backend used for the LLM path) and
 * pre-populates the whisper tensor names, then constructs this
 * wrapper. Encoding and decoding share the backend handle —
 * nothing special-cased on the JS side.
 */
export class WasmWhisperPipeline {
    free(): void;
    [Symbol.dispose](): void;
    /**
     * Run one decoder step and return the real next-token logits.
     */
    decode_step_logits(token: number, pos: number): Float32Array;
    /**
     * Run the encoder. `mel` is a `Float32Array` of length
     * `n_mels * n_frames` (typically `80 * 3000 = 240_000`).
     * Returns a `Float32Array` of length
     * `n_audio_ctx * encoder_hidden_dim` (typically
     * `1500 * 384 = 576_000` for whisper-tiny).
     */
    encode(mel: Float32Array): Float32Array;
    /**
     * Greedy autoregressive decode. Returns the generated token
     * ids (BOS excluded). Stops at `eos_token` or after
     * `max_tokens` steps, whichever fires first.
     */
    generate(encoder_output: Float32Array, max_tokens: number, eos_token: number): Uint32Array;
    /**
     * Prime cross-attention K/V from an encoder output and reset the
     * autoregressive self-attention cache for a new utterance.
     */
    load_audio_context(encoder_output: Float32Array): void;
    memo_clear(): void;
    memo_enable(on: boolean): void;
    memo_stats(): Uint32Array;
    /**
     * Construct from a `WasmHostBackend` and a JSON config string.
     *
     * `backend` is taken by reference (not by value) so the JS
     * handle stays alive for `set_tensor` / `evict` calls that
     * run between the encoder pass and the decode loop. Same
     * rationale as `WasmLlamaPipeline::from_backend` — taking
     * the wrapper by value triggers a `__rt::throw_null` panic
     * on the next `set_tensor` because wasm-bindgen zeros
     * `__wbg_ptr` on consumed wrappers.
     *
     * `config_json` is the stringified `WhisperConfig` (see Agent
     * D). Either `{ "config": {...} }` or the bare config object
     * is accepted.
     */
    constructor(backend: WasmHostBackend, config_json: string);
    /**
     * Reset only the autoregressive decoder self-attention cache.
     */
    reset_decoder(): void;
    /**
     * Override the BOS token used by the next `generate` call.
     * Defaults to `50258` (multilingual). Set to `50257` for
     * `whisper-*.en` checkpoints, or any other special-token id
     * for forced-prompt experiments.
     */
    set_bos_token(bos: number): void;
    /**
     * Override the forced decoder prefix used by the next `generate`
     * call. Defaults to `[50258, 50259, 50359, 50363]`
     * (`<|sot|><|en|><|transcribe|><|notimestamps|>`). Pass an empty
     * array to restore legacy BOS-only seeding, or a custom prefix
     * for other languages / translation / timestamped decoding.
     */
    set_forced_prefix(prefix: Uint32Array): void;
}

/**
 * F-mesh-2 instrumentation (COLTRANE_MESH_FALSIFICATION_LEDGER): install
 * the panic hook at WASM module instantiation, BEFORE any export is
 * called. The previous regime installed it lazily inside
 * `WasmHostBackend::new` and `WasmGemma4Pipeline::from_backend`, which
 * left a window where `parse_tensors_json` / `parse_config_json` (the
 * FIRST exports the worker boot calls — see
 * `apps/distributed-inference-worker/src/index.ts:327-334`) could
 * panic with the runtime emitting a bare `RuntimeError: unreachable`
 * and no source line. With `--target web`, wasm-bindgen invokes
 * `start` synchronously as part of `wasmGlue.default(wasmModule)`,
 * so by the time the JS host calls any export the hook is already
 * in place. `set_once` is idempotent so leaving the existing
 * `install_panic_hook()` calls in `new` / `from_backend` is harmless
 * belt-and-braces — kept so a future caller that bypasses module
 * init (e.g. `WebAssembly.instantiate` without the bindgen wrapper)
 * still gets the hook on first use.
 */
export function __dii_init(): void;

export function buley_route(v1_val: any, v2_val: any): any;

export function buley_siphon(source_val: any, attractor_val: any): any;

/**
 * 6-char hex for `bw_cache_fp24_frf_v1` final digest.
 */
export function bw_cache_fp24_frf_hex_v1(data: Uint8Array): string;

/**
 * 3-byte little-endian FRF fingerprint, masked to 24 bits.
 */
export function bw_cache_fp24_frf_v1(data: Uint8Array): Uint8Array;

/**
 * 6-char lowercase hex fingerprint (low 24 bits of `bw_cache_fp64_hex_v1`).
 */
export function bw_cache_fp24_hex_v1(data: Uint8Array): string;

/**
 * 3-byte (24-bit) little-endian cache fingerprint — the byte-clean floor below
 * `bw_cache_fp64_v1`. Half the wire of fp48, a quarter of fp64. UNSOUND
 * standalone (~2^12 birthday); ship only as a context-keyed front channel with
 * verify-on-hit (TS `contextKeyedFp24` / `verifyFp24OnHit`).
 */
export function bw_cache_fp24_v1(data: Uint8Array): Uint8Array;

/**
 * 16-char hex for `bw_cache_fp64_frf_v1` final digest.
 */
export function bw_cache_fp64_frf_hex_v1(data: Uint8Array): string;

export function bw_cache_fp64_frf_v1(data: Uint8Array): Uint8Array;

/**
 * 16-char lowercase hex fingerprint (same algorithm as `bw_cache_fp64_v1`).
 */
export function bw_cache_fp64_hex_v1(data: Uint8Array): string;

/**
 * 8-byte little-endian cache fingerprint (XXH64). Smaller KV keys than SHA-256 hex.
 */
export function bw_cache_fp64_v1(data: Uint8Array): Uint8Array;

/**
 * Compute compression ratio: text bytes vs packed bytes.
 * Per zero_overhead theorem: packed ≤ text (always).
 */
export function compression_ratio(text_length: number): number;

/**
 * Decode a FlowFrame flags byte into (structure_type, bit_width_nibble).
 */
export function decode_flags(flags: number): Uint8Array;

/**
 * Decode a FlowFrame header, returning
 * [stream_id_hi, stream_id_lo, pos_b3, pos_b2, pos_b1, pos_b0,
 *  structure_type, bit_width_nibble, len_b2, len_b1, len_b0].
 */
export function decode_flowframe_header(frame: Uint8Array): Uint8Array;

/**
 * Decode a FlowFrame stream_id into (dimension, chromosome).
 */
export function decode_helix_stream_id(stream_id: number): Uint8Array;

/**
 * Generate dilated sampling positions for a genomic range.
 *
 * Given a start position, length, and dilation strategy, returns
 * the positions at which this dimension should be sampled.
 */
export function dilated_positions(start: number, length: number, stride: number): Uint32Array;

/**
 * Encode a FlowFrame flags byte from structure type and bit-width.
 *
 * flags = (structure_type << 4) | bit_width_nibble
 *
 * Structure types (upper nibble):
 *   0x1_ = PROCESS (default stream data)
 *   0x2_ = FORK    (stream split)
 *   0x4_ = FOLD    (stream merge)
 *   0x8_ = VENT    (stream termination)
 */
export function encode_flags(structure_type: number, bit_width_nibble: number): number;

/**
 * Encode packed DNA bases into an Aeon FlowFrame.
 *
 * FlowFrame header (10 bytes):
 *   [stream_id:2][sequence:4][flags:1][length:3]
 *
 * stream_id = chromosome number (1-25)
 * sequence  = genomic position / window_size
 * flags     = structure type
 * payload   = packed bases for this window
 */
export function encode_flowframe(chromosome: number, position: number, flags: number, payload: Uint8Array): Uint8Array;

/**
 * Encode a dimension index and chromosome into a FlowFrame stream_id.
 *
 * Layout: `(dimension << 8) | chromosome`
 * - dimension: 0-53 (upper byte)
 * - chromosome: 1-25 typical (lower byte)
 */
export function encode_helix_stream_id(dimension: number, chromosome: number): number;

/**
 * Encode a typed FlowFrame with explicit bit-width in the flags byte.
 *
 * This is the general-purpose version of encode_flowframe that embeds
 * the encoding width so decoders know how to interpret the payload.
 */
export function encode_typed_flowframe(stream_id: number, position: number, structure_type: number, bit_width_nibble: number, payload: Uint8Array): Uint8Array;

/**
 * Convert a full FASTA sequence into a stream of FlowFrames.
 * One frame per window_size bases.
 */
export function fasta_to_flowframes(sequence: Uint8Array, chromosome: number, start_position: number, window_size: number): Uint8Array;

/**
 * Compute the 3D helical coordinates (x, y, z) for a genomic position.
 *
 * x = R * cos(phase)
 * y = R * sin(phase)
 * z = position * rise_per_bp
 *
 * where R = 10 angstroms (radius of B-form DNA double helix).
 * Returns [x, y, z] in angstroms.
 */
export function helix_coordinates(position: number): Float64Array;

/**
 * Compute the helical phase angle (radians) for a genomic position.
 *
 * The B-form DNA helix completes one full turn every 10.5 bp.
 * Phase = (position mod 10.5) * (2π / 10.5)
 *
 * This maps each base to its rotational position around the helix axis,
 * enabling rotationally-aware sampling and analysis.
 */
export function helix_phase(position: number): number;

/**
 * Q4_K dispatch — symmetry with `mat_vec_q6k_dispatch` for shards whose
 * `output_weight` (or fallback `token_embd_weight`) is Q4_K rather than
 * Q6_K. Goes through the wave-22 wasm32 SIMD `mat_vec_q4k_row`.
 */
export function mat_vec_q4k_dispatch(x: Float32Array, w: Uint8Array, n: number, d: number): Float32Array;

/**
 * Q6_K dispatch — calls `crate::math::mat_vec_q6k` over the supplied
 * residual + quantised weight slice. The wasm32 build picks up the
 * SIMD branch in `mat_vec_q6k_row` automatically.
 */
export function mat_vec_q6k_dispatch(x: Float32Array, w: Uint8Array, n: number, d: number): Float32Array;

/**
 * Count mutations between two packed sequences via XOR.
 * Per xor_detects_mutations: XOR = 0 iff sequences are identical.
 * Returns the number of differing bases.
 */
export function mutation_count(seq_a: Uint8Array, seq_b: Uint8Array, length: number): number;

/**
 * Pack values into 4-bit encoding. 2 values per byte, MSB first.
 * Values are clamped to 0-15. For 16-level quantized data.
 */
export function pack_4bit(values: Uint8Array): Uint8Array;

/**
 * Pack annotation values (0-3 each, 2 bits) into bytes, same as base packing.
 * This reuses the 2-bit packing scheme for all dimension channels:
 * value 0 = low/absent, 1 = low-medium, 2 = medium-high, 3 = high/present.
 */
export function pack_annotation(values: Uint8Array): Uint8Array;

/**
 * Pack a DNA sequence into 2-bit binary. 4 bases per byte.
 * Per two_bit_four_per_byte theorem: 4 * 2 = 8.
 */
export function pack_bases(sequence: Uint8Array): Uint8Array;

/**
 * Pack f64 values into bytes (big-endian IEEE 754).
 */
export function pack_f64(values: Float64Array): Uint8Array;

/**
 * Pack u16 values into bytes (big-endian).
 */
export function pack_u16(values: Uint16Array): Uint8Array;

/**
 * Pack u32 values into bytes (big-endian).
 */
export function pack_u32(values: Uint32Array): Uint8Array;

/**
 * Parse a knot metadata JSON string and return the optional `config` block
 * as a stringified `KnotConfig`, or `null` if absent.
 */
export function parse_config_json(metadata_json: string): string | undefined;

/**
 * Parse a FASTA record: extract header and pack the sequence.
 * Returns (header, packed_bases, sequence_length).
 */
export function parse_fasta_record(input: Uint8Array): any;

/**
 * Parse a knot metadata JSON string and return the `tensors` map as a
 * stringified JSON object: `{ name: { offset, length, tensor_type }, ... }`.
 * Lets the JS host keep the parsed map without re-implementing the field
 * renames (`type` → `tensor_type`) on the JS side.
 */
export function parse_tensors_json(metadata_json: string): string;

/**
 * Perfect-phase-lock predicate: returns `true` iff `r ∈ {17, 34, 51}`.
 * Mirrors the Lean `is_perfect_phase_lock` decidable. Use this to gate
 * `perfect_phase_lock_witness_score_r` (which returns `0` for both
 * "not in set" and "score=0", a degenerate but legal witness reading).
 */
export function perfect_phase_lock_check_r(r: number): boolean;

/**
 * Score of `constructive_interference(a, b)` for two `BuleyUnit`s
 * supplied as flat `(rim, void, rigidity)` triples. Pointwise
 * saturating add of all three fields, then sum. Mirrors the Lean
 * `constructive_interference` definition.
 */
export function perfect_phase_lock_constructive(a_rim: number, a_void: number, a_rigidity: number, b_rim: number, b_void: number, b_rigidity: number): number;

/**
 * Score of `destructive_interference(a, b)` for two `BuleyUnit`s
 * supplied as flat `(rim, void, rigidity)` triples. Pointwise
 * saturating subtract of all three fields, then sum. At `a == b`
 * (and in particular at the witness `⟨r, 0, 0⟩` against itself for
 * any perfect `r`) this returns `0` — the death-of-interference
 * collapse from Lean `death_of_interference`.
 */
export function perfect_phase_lock_destructive(a_rim: number, a_void: number, a_rigidity: number, b_rim: number, b_void: number, b_rigidity: number): number;

/**
 * Score of the Lean death-of-interference witness at density `r`.
 * Returns `witness.score()` (which equals `r`) when `r` is a perfect
 * density, else `0`. Pair with `perfect_phase_lock_check_r` to
 * distinguish the "no witness" case from a legitimate zero score.
 */
export function perfect_phase_lock_witness_score_r(r: number): number;

/**
 * Evaluate the scattering amplitude `⟨pluckerVector(plane), dual⟩`.
 * `dual` is zip-truncated against the Plücker vector (List.zip semantics),
 * matching the Lean `scatteringAmplitude` definition. Returns `0` on
 * validation failure (the empty inner product) — pair with
 * `scattering_kplane_validate` if you need to distinguish "real zero"
 * from "validation failure".
 */
export function scattering_amplitude_eval(k: number, d: number, rows_flat: BigInt64Array, dual: BigInt64Array): bigint;

/**
 * Decidable positivity check for Gr⁺(k, d) membership. Returns `true`
 * iff every Plücker coordinate is strictly `> 0`. Returns `false` on
 * validation failure (matches the Lean `isPositiveBool` boundary
 * semantics: a malformed plane is not positive).
 */
export function scattering_is_positive(k: number, d: number, rows_flat: BigInt64Array): boolean;

/**
 * Validate a flattened k-plane: returns `true` iff `rows_flat.len() == k * d`
 * AND `KPlane::new(k, d, ...)` succeeds. Mirrors the implicit precondition
 * of every other `scattering_*` call in this module.
 */
export function scattering_kplane_validate(k: number, d: number, rows_flat: BigInt64Array): boolean;

/**
 * Compute the Plücker vector of the supplied k-plane. Returns one entry
 * per ordered k-subset of `[0..d)`, in `k_subsets` order (reverse-lex).
 * Returns an empty vector if the plane fails validation — callers should
 * either call `scattering_kplane_validate` first or check `is_empty()`.
 */
export function scattering_plucker_vector(k: number, d: number, rows_flat: BigInt64Array): BigInt64Array;

/**
 * Vertex count of Gr⁺(k, d), i.e. `(k_subsets k d).len()` = `C(d, k)`.
 * Pure combinatorial helper — no plane data needed. Mirrors the Lean
 * `vertexCount` definition; the Lean coverage sweep oracle pins the
 * values `(2,4)→6, (2,6)→15, (2,8)→28, (3,6)→20, (3,9)→84, (3,12)→220`.
 */
export function scattering_vertex_count(k: number, d: number): number;

/**
 * Search for a DNA pattern in packed binary using word-parallel matching.
 * Compares 32 bases per u64 word via XOR.
 *
 * Per word_parallel_speedup: 32x faster than character-by-character.
 * Per xor_detects_mutations: XOR produces nonzero exactly at mismatches.
 *
 * Returns byte offsets where the pattern matches.
 */
export function search_packed(haystack: Uint8Array, haystack_len: number, needle: Uint8Array, needle_len: number): Uint32Array;

/**
 * Search for a DNA pattern directly inside a Syzygy-folded structure.
 *
 * Logarithmic performance: Because Syzygy evaluates DNA topologically, it skips
 * over interior data natively. If a structure is 1,000,000 repetitions long,
 * the algorithm logically resolves its interior in O(1) math without iterating
 * characters or allocating expansion memory.
 */
export function search_syzygy(folded: Uint8Array, needle: Uint8Array): Uint32Array;

/**
 * Solve the relative pose of camera2 vs camera1 from two **grayscale** frames
 * (`u8`, row-major, length `width*height` each). Returns a [`WasmSfmResult`]
 * with a JSON pose or an honest null. Never fabricates a pose.
 *
 * `fast_threshold` / `min_parallax_deg` of 0 select the [`SfmConfig::default`]
 * values (handy for the JS caller that doesn't want to tune).
 */
export function sfmSolve(gray1: Uint8Array, gray2: Uint8Array, width: number, height: number, fast_threshold: number, min_parallax_deg: number): WasmSfmResult;

/**
 * Execute a Syzygy Fold (Pass 59) on a raw DNA sequence.
 *
 * Converts a 1D incompressible string into a topological invariant manifold
 * by dilating into 2-bit crossings and executing a structural RLE collapse
 * (e.g. Poly-A -> O(1) complexity).
 */
export function syzygy_fold(sequence: Uint8Array): Uint8Array;

/**
 * Execute a Syzygy Fold on an arbitrary binary sequence (General Purpose Archiver)
 * Drops the DNA-specific 2-bit packing to compress standard desktop byte streams.
 */
export function syzygy_fold_binary(sequence: Uint8Array): Uint8Array;

/**
 * Fold arbitrary binary data into a 54-dimension FlowFrame stream.
 *
 * Each byte is assigned to dimension (byte_index % 54). Bytes within each
 * dimension are windowed into FlowFrames of up to 1024 bytes each. The
 * position field encodes the original byte offset so the unfold can
 * reconstruct exact ordering.
 */
export function syzygy_fold_structural(sequence: Uint8Array): Uint8Array;

/**
 * Smush: Topological Compression followed by AEAD Encryption.
 * Perfect security plus topological efficiency in one pass.
 */
export function syzygy_smush(sequence: Uint8Array, key_phrase: string): Uint8Array;

/**
 * Unfold a Syzygy binary buffer back into 1D raw bases.
 */
export function syzygy_unfold(folded: Uint8Array, original_length: number): Uint8Array;

/**
 * Unfold a generalized Syzygy binary buffer back into arbitrary byte octets.
 */
export function syzygy_unfold_binary(folded: Uint8Array, original_length: number): Uint8Array;

/**
 * Unfold a 54-dimension FlowFrame stream back into raw bytes.
 *
 * Parses the BWFF header, walks FlowFrames, extracts per-dimension payloads,
 * and reassembles bytes in their original order using the round-robin pattern.
 */
export function syzygy_unfold_structural(stream: Uint8Array, original_length: number): Uint8Array;

/**
 * Unsmush: Securely decrypt and unfold back to raw octets.
 */
export function syzygy_unsmush(smushed: Uint8Array, key_phrase: string, original_length: number): Uint8Array;

/**
 * Unpack 4-bit values back to a vector.
 */
export function unpack_4bit(packed: Uint8Array, length: number): Uint8Array;

/**
 * Unpack 2-bit annotation values back to a vector.
 */
export function unpack_annotation(packed: Uint8Array, length: number): Uint8Array;

/**
 * Unpack 2-bit binary back to DNA sequence.
 * Per pack_unpack theorem: round-trip is identity.
 */
export function unpack_bases(packed: Uint8Array, length: number): Uint8Array;

/**
 * Unpack bytes into f64 values (big-endian IEEE 754).
 */
export function unpack_f64(packed: Uint8Array, count: number): Float64Array;

/**
 * Unpack bytes into u16 values (big-endian).
 */
export function unpack_u16(packed: Uint8Array, count: number): Uint16Array;

/**
 * Unpack bytes into u32 values (big-endian).
 */
export function unpack_u32(packed: Uint8Array, count: number): Uint32Array;

/**
 * Blend: `0` = SourceOver, `1` = Multiply (see [`BlendMode`]).
 */
export function wasmCompositeMaskedRgb(bg: Float32Array, fg: Float32Array, alpha: Float32Array, width: number, height: number, blend_mode: number): Float32Array;

/**
 * Estimate the motion PSF `[angle_deg, length_px]` from row-major linear RGB `[0,1]`.
 */
export function wasmEstimateMotionPsf(rgb: Float32Array, width: number, height: number): Float32Array;

/**
 * **Manifold Calibration**: High-dimensional White/Black Balance via WASM.
 */
export function wasmManifoldCalibrationApply(rgb: Float32Array, topology_alpha: Float32Array, width: number, height: number, r_shift: number, g_shift: number, b_shift: number, pedestal_persistence: number): WasmTopologicalCalibrationResult;

/**
 * Mask multiply: `dst = src * alpha` per RGB channel (`alpha` per pixel).
 */
export function wasmMaskMultiplyRgb(src: Float32Array, alpha: Float32Array, width: number, height: number): Float32Array;

/**
 * `rgb`: row-major linear RGB in `[0,1]`, length `width * height * 3`.
 * `monocular_cue_blend`: forwarded to [`MeshDepthConfig::monocular_cue_blend`] (0 = off).
 */
export function wasmMeshDepthConfidenceRgbF32(rgb: Float32Array, width: number, height: number, monocular_cue_blend: number): WasmMeshDepthStyleResult;

/**
 * Topology/depth-gated residual deblur over row-major linear RGB `[0,1]`.
 */
export function wasmMeshResidualDeblurRgbF32(rgb: Float32Array, width: number, height: number, overpotential: number, admission_floor: number, saturation_limit: number, depth_confidence_blend: number): WasmMeshResidualDeblurResult;

/**
 * **Monster LUT**: 66-Chord Topological Grading via WASM.
 */
export function wasmMonsterLutApply(rgb: Float32Array, topology_alpha: Float32Array, width: number, height: number, lut_66_weights: Float32Array): WasmTopologicalCalibrationResult;

/**
 * Richardson–Lucy line-PSF motion deblur over row-major linear RGB `[0,1]`.
 */
export function wasmMotionDeblurRgbF32(rgb: Float32Array, width: number, height: number, angle_deg: number, length_px: number, iterations: number, damping: number, emit_layers: boolean): WasmMotionDeblurResult;

export function wasmRelightLambertMasked(rgb: Float32Array, plane: Float32Array, topology_alpha: Float32Array, width: number, height: number, light_x: number, light_y: number, light_z: number, diffuse_strength: number, ambient: number): Float32Array;

/**
 * **Topological Recompositioning**: Relight using high-dimensional harmonic potential.
 */
export function wasmRelightMonsterMeshMasked(rgb: Float32Array, topology_alpha: Float32Array, width: number, height: number, overpotential: number, harmonic_threshold: number): WasmRelightMonsterMeshResult;

/**
 * `rgb`: row-major unit linear floats `width * height * 3`.
 */
export function wasmTopologyMaskBuildRgbF32(rgb: Float32Array, width: number, height: number): WasmTopologyMaskResult;
